import type { AccountSearchRecord } from '@linm-soft-org/linm-web-common-components';
import type { AccountDto } from '../../services/kt/models';

export function mapAccountSearchRecord(a: AccountDto): AccountSearchRecord {
  return {
    code: a.code,
    name: a.name,
    parentCode: a.parentCode,
    level: a.level,
    isDetail: a.isDetail,
    isActive: a.isActive,
    isSelectable: a.isSelectable ?? true,
    disabledReason: a.disabledReason,
    warningReason: a.warningReason,
    resolvedStandard: a.resolvedStandard,
  };
}
